// ─── IMPORT ────────────────────────────────────────────────────────────────────

async function importData() {
  const { createClient } = await import("@supabase/supabase-js");
  const supabase = createClient(SUPABASE_URL, SERVICE_ROLE_KEY);

  // Import từng batch 50 để tránh timeout
  const BATCH = 50;

  console.log(`\n📥 Bắt đầu import ${PERSONS.length} thành viên...`);
  for (let i = 0; i < PERSONS.length; i += BATCH) {
    const batch = PERSONS.slice(i, i + BATCH);
    const { error } = await supabase.from("persons").upsert(batch, { onConflict: "id" });
    if (error) { console.error(`❌ Lỗi batch persons [${i}]:`, error.message); }
    else { console.log(`  ✅ Persons ${i + 1}–${Math.min(i + BATCH, PERSONS.length)}`); }
  }

  console.log(`\n📥 Bắt đầu import ${RELATIONSHIPS.length} quan hệ...`);
  for (let i = 0; i < RELATIONSHIPS.length; i += BATCH) {
    const batch = RELATIONSHIPS.slice(i, i + BATCH);
    const { error } = await supabase.from("relationships").upsert(batch, { onConflict: "id" });
    if (error) { console.error(`❌ Lỗi batch relationships [${i}]:`, error.message); }
    else { console.log(`  ✅ Relationships ${i + 1}–${Math.min(i + BATCH, RELATIONSHIPS.length)}`); }
  }

  console.log("\n🎉 Import hoàn tất!");
  process.exit(0);
}

importData().catch(e => { console.error(e); process.exit(1); });
